SELECT ?eventLabel WHERE {
  wd:Q4833805 wdt:P118 wd:Q3000357.
  wd:Q16823400 wdt:P118 wd:Q3000357;
                wdt:P585 "2013-01-01T00:00:00Z"^^xsd:dateTime.
  wd:Q3000357 rdfs:label ?eventLabel.
